import { Box } from "@mui/material";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function DashboardLayout({ children }) {
  return (
    <Box sx={{ display: "flex" }}>
      {/* Sidebar */}
      <Sidebar />

      {/* Main Content */}
      <Box
        component="main"
        sx={{
          flexGrow: 1,
          ml: "220px", // 👈 important (same as sidebar width)
          minHeight: "100vh",
          background: "#f5f5f5",
        }}
      >
        <Topbar />

        <Box sx={{ p: 3 }}>{children}</Box>
      </Box>
    </Box>
  );
}
